### Implement Automatic Payments with TypeScript Fetch

Source: https://context7.com/coinbase/x402/llms.txt

Wraps the native fetch API to intercept 402 status codes and automatically sign payments using EVM or Solana schemes. It requires an initialized x402 client and returns the standard Response object with optional payment headers.

```typescript
import { x402Client, wrapFetchWithPayment } from "@x402/fetch";
import { ExactEvmScheme } from "@x402/evm/exact/client";
import { ExactSvmScheme } from "@x402/svm/exact/client";
import { privateKeyToAccount } from "viem/accounts";
import { createKeyPairSignerFromBytes } from "@solana/kit";
import { getBytes } from "@solana/codecs";
import bs58 from "bs58";

const evmSigner = privateKeyToAccount("0xac0974bec39a17e36ba4a6b4d238ff944bacb478cbed5efcae784d7bf4f2ff80");
const svmKeyBytes = bs58.decode("4NMwxzmYj2uvHuq8xoqhY8RXg63KSVJM1DXkpbmkUY7YQWuoyQgFnnzn6yo3CMnqZasnNPNuAT2TLwQsCaKkUddp");
const svmSigner = await createKeyPairSignerFromBytes(getBytes(svmKeyBytes));

const client = new x402Client();
client.register("eip155:*", new ExactEvmScheme(evmSigner));
client.register("solana:*", new ExactSvmScheme(svmSigner));

const fetchWithPayment = wrapFetchWithPayment(fetch, client);

async function getWeatherData() {
  const response = await fetchWithPayment("https://api.example.com/weather");
  if (!response.ok) throw new Error(`Request failed: ${response.status}`);
  return await response.json();
}
```

